{
  "name": "pi-boomerang",
  "version": "0.2.1",
  "description": "Token-efficient autonomous task execution with context collapse",
  "type": "module",
  "keywords": ["pi-package"],
  "files": [
    "index.ts",
    "README.md",
    "CHANGELOG.md",
    "banner.png"
  ],
  "scripts": {
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "devDependencies": {
    "vitest": "^2.0.0",
    "@mariozechner/pi-coding-agent": "*",
    "@mariozechner/pi-ai": "*"
  },
  "pi": {
    "extensions": ["./index.ts"]
  }
}

